import React from "react";
import Plus2 from "../../../assets/images/DashboardImgs/plus-square.png";
import Work from "../../../assets/images/DashboardImgs/work.png";
import moment from 'moment';
import Pencil from "../../../assets/images/DashboardImgs/pencil1.png";
import CustomModal from "../../../Components/Modal";
import DegreeTitle from "../../../assets/images/degree-title.png";
import Polygon2 from "../../../assets/images/angle-down.png";
import DegreeTitle2 from "../../../assets/images/degree-levels.png";
import Building from "../../../assets/images/building1.png";
import MapPin from "../../../assets/images/map-pin.png";
import Calendar from "../../../assets/images/calendar.png";
import Percent from "../../../assets/images/percent.png";
import ApiRequest from "../../../Services/ApiRequest";



class EducationCard extends React.Component {
    state = {
        show: false,
        education: [],
        modalBtnText: 'Save',
        error: {},
        eduId:''
    }
    static getDerivedStateFromProps(props, state) {
        return {
            education: props.personalInfo?.[0]?.education,
        };
    }
    education = () => {
        if (this.state?.education?.length) {
            return this.state?.education.map(el => {
                return (
                    <>
                        <h4>{el.degree_title}<span>&nbsp; {moment(el.year_completion).format("MMM Do YY")}</span> <img className="cursor-pointer" src={Pencil} alt="" onClick={() => this.onEditEdu(el.id)} /></h4>
                        <h6>{el.institute}</h6>
                        <p>Porttitor amet massa Done cporttitor dolor et nisl molestie ium feliscon lore
                            ipsum dolor tfringilla. lorem lorem ipsum. </p>
                        <hr />
                    </>
                )
            })
        }
    }
    handleModalClose = () => {
        this.setState({
            show: !this.state.show,
            degree_title: '',
            degree_level: '',
            institute: '',
            location: '',
            year_completion: '',
            type: '',
            marks: '',
            modalBtnText: 'Save'

        })
    }
    handleChange = (e) => {
        const { name, value } = e.target;
        this.setState({
            [name]: value
        })
    }
    handleSubmit = async (e) => {
        e.preventDefault();
        const { degree_title, degree_level, institute, location, year_completion, type, marks } = this.state;
        let { degreeTitleError, degreeLevelError, instituteError, locationError, yearCompletionError, typeError, marksError } = '';
        if (!degree_title) {
            degreeTitleError = "This field is required."
        }
        if (!degree_level) {
            degreeLevelError = "This field is required."
        }
        if (!institute) {
            instituteError = "This field is required."
        }
        if (!location) {
            locationError = "This field is required."
        }
        if (!year_completion) {
            yearCompletionError = "This field is required."
        }
        if (!type) {
            typeError = "This field is required."
        }
        if (!marks) {
            marksError = "This field is required."
        }
        this.setState({
            error: {
                degreeTitleError: degreeTitleError,
                degreeLevelError: degreeLevelError,
                instituteError: instituteError,
                locationError: locationError,
                typeError: typeError,
                yearCompletionError: yearCompletionError,
                marksError: marksError,
            }
        });
        if (degreeTitleError || degreeLevelError || instituteError || locationError || yearCompletionError || typeError || marksError) {
            return
        }
        const response = await ApiRequest.postRequest(`/addEducation`, { degree_title, degree_level, institute, location, year_completion, type, marks })
        if (response && response.status === 200) {
            this.props.onChange();
            this.handleModalClose();
        }


    }
    // Edit Card
    onEditEdu = async (id) => {
        const response = await ApiRequest.getRequest('/geteducation/' + id);
        console.log(response);
        if (response && response.status === 200) {
            const val = response.data.educationDetails;
            this.setState({
                degree_title: val.degree_title,
                degree_level: val.degree_level,
                institute: val.institute,
                location: val.location,
                year_completion: val.year_completion,
                type: val.type,
                marks: val.marks,
                show: !this.state.show,
                modalBtnText: 'Update',
                eduId:id

            })
        }

    }
    handleUpdate = async(e) => {
        e.preventDefault();
        const { degree_title, degree_level, institute, location, year_completion, type, marks } = this.state;
        let { degreeTitleError, degreeLevelError, instituteError, locationError, yearCompletionError, typeError, marksError } = '';
        if (!degree_title) {
            degreeTitleError = "This field is required."
        }
        if (!degree_level) {
            degreeLevelError = "This field is required."
        }
        if (!institute) {
            instituteError = "This field is required."
        }
        if (!location) {
            locationError = "This field is required."
        }
        if (!year_completion) {
            yearCompletionError = "This field is required."
        }
        if (!type) {
            typeError = "This field is required."
        }
        if (!marks) {
            marksError = "This field is required."
        }
        this.setState({
            error: {
                degreeTitleError: degreeTitleError,
                degreeLevelError: degreeLevelError,
                instituteError: instituteError,
                locationError: locationError,
                typeError: typeError,
                yearCompletionError: yearCompletionError,
                marksError: marksError,
            }
        });
        if (degreeTitleError || degreeLevelError || instituteError || locationError || yearCompletionError || typeError || marksError || !this.state.eduId) {
            return
        }
        const response = await ApiRequest.postRequest(`/addEducation/${this.state.eduId}`, { degree_title, degree_level, institute, location, year_completion, type, marks })
        if (response && response.status === 200) {
            this.props.onChange();
            this.handleModalClose();
        }
    }
    render() {
        return (
            <>
                <div className="row mar-width-0 bg-profile">
                    <div className="row mar-width-0 ProfileInner3-1">
                        <div className="col-md-6">
                            <h5><img src={Work} alt="" /> Education</h5>
                        </div>
                        <div className="col-md-6 text-right">
                            <img className="plus-skills cursor-pointer" onClick={() => this.handleModalClose()} src={Plus2} alt="" />
                        </div>
                    </div>
                    <div className="row mar-width-0 ProfileInner3-2">
                        {this.education()}
                    </div>
                </div>
                <CustomModal show={this.state.show} closeBtn={this.handleModalClose} heading="Education Modal" onSubmit={this.handleSubmit} btnText={this.state.modalBtnText} onUpdate={this.handleUpdate}>
                    <div className="form_section_one  form-wrap form-section">

                        <div className="row ">
                            <div className="col-md-12">
                                <div className="form-group position-relative">
                                    <label htmlFor="exampleInputEmail11">Degree Title</label>
                                    <div className={`select-style-2 w-100`} >
                                        <select name="degree_title" onChange={this.handleChange} value={this.state.degree_title}>
                                            <option disable>Select options</option>
                                            <option value="Bachelor of Biochemistry">Bachelor of Biochemistry</option>
                                            <option value="Bachelor of Science in Computer Science">Bachelor of Science in Computer Science</option>
                                            <option value="Master of Business Administration">Master of Business Administration</option>
                                        </select>
                                        <img src={DegreeTitle} className="user-icon2" alt="" />
                                        <img src={Polygon2} className="Polygon-icon" alt="" />
                                    </div>
                                    <span className="error">{this.state.error.degreeTitleError}</span>
                                </div>
                            </div>
                            <div className="col-md-12">
                                <div className="form-group">
                                    <label htmlFor="exampleInputEmail13">Degree Level</label>
                                    <div className={`select-style-2 w-100 ${this.state.error.degreeTitleError ? 'error-border' : ''}`}>
                                        <select name="degree_level" onChange={this.handleChange} value={this.state.degree_level}>
                                            <option disable>Select options</option>
                                            <option value="Undergraduate">Undergraduate</option>
                                            <option value="Graduate">Graduate</option>
                                        </select>
                                        <img src={DegreeTitle2} className="user-icon2" alt="" />
                                        <img src={Polygon2} className="Polygon-icon" alt="" />
                                    </div>
                                    <span className="error">{this.state.error.degreeLevelError}</span>
                                </div>
                            </div>

                            <div className="col-md-12">
                                <div className="form-group position-relative">
                                    <label htmlFor="exampleInputEmail11">Institute</label>
                                    <input type="text"
                                        className={`form-control ${this.state.error.instituteError ? 'error-border' : ''}`} id="exampleInputEmail11"
                                        name="institute" onChange={this.handleChange} value={this.state.institute}
                                    />
                                    <img src={Building} className="user-icon" alt="" />
                                    <span className="error">{this.state.error.instituteError}</span>
                                </div>
                            </div>

                            <div className="col-md-6">
                                <div className="form-group position-relative">
                                    <label htmlFor="exampleInputEmail11">Location</label>
                                    <input type="text" name="location" className={`form-control ${this.state.error.locationError ? 'error-border' : ''}`} id="exampleInputEmail11"
                                        value={this.state.location}
                                        onChange={this.handleChange}
                                    />
                                    <img src={MapPin} className="user-icon" alt="" />
                                    <span className="error">{this.state.error.locationError}</span>
                                </div>
                            </div>

                            <div className="col-md-6 ">
                                <div className="form-group position-relative">
                                    <label htmlFor="exampleInputEmail11">Year Completion</label>
                                    <input type="date" name="year_completion" className={`form-control date ${this.state.error.yearCompletionError ? 'error-border' : ''}`} id="exampleInputEmail11"
                                        value={this.state.year_completion}
                                        onChange={this.handleChange}
                                    />
                                    <img src={Calendar} className="user-icon" alt="" />
                                    <span className="error">{this.state.error.yearCompletionError}</span>
                                </div>
                            </div>
                            <div className="col-md-6 radio-wrap align-self-center">
                                <span>
                                    <input type="radio" id="test1"
                                        className={`form-control ${this.state.error.typeError ? 'error-border' : ''}`}
                                        onChange={this.handleChange}
                                        name="type"
                                        value="cgpa"
                                        checked={this.state.type === 'cgpa' ? true :false}
                                    />
                                    <label htmlFor="test1">CGPA</label>
                                </span>
                                <span>
                                    <input type="radio" id="test2"
                                        className={`form-control ${this.state.error.typeError ? 'error-border' : ''}`}
                                        name="type"
                                        value="percentage"
                                        onChange={this.handleChange}
                                        checked={this.state.type === 'percentage' ? true :false}

                                    />
                                    <label htmlFor="test2">Percentage</label>
                                </span>
                                <span className="error">{this.state.error.typeError}</span>
                            </div>

                            <div className="col-md-6">
                                <div className="form-group position-relative">
                                    <label htmlFor="exampleInputEmail11">CGPA / Percentage</label>
                                    <input type="number" name="marks" className={`form-control ${this.state.error.marksError ? 'error-border' : ''}`} id="exampleInputEmail11"
                                        onChange={this.handleChange}
                                        value={this.state.marks}
                                    />
                                    <img src={Percent} className="user-icon" alt="" />
                                    <span className="error">{this.state.error.marksError}</span>

                                </div>
                            </div>
                        </div>
                    </div>

                </CustomModal>
            </>
        )
    }
}

export default EducationCard;