import React from 'react';
import './profile.css';
import Pencil from "../../../assets/images/DashboardImgs/pencil1.png";
import Twit2 from "../../../assets/images/DashboardImgs/twitter2.png";
import Fb2 from "../../../assets/images/DashboardImgs/fb2.png";
import Rectangle from "../../../assets/images/DashboardImgs/Rectangle.png";
import HeaderMenteeDashboard from "../../../Components/Layouts/DashboardLayout/MenteeLayout/HeaderMenteeDashboard";
import MenteeSidebar from "../../../Components/Layouts/DashboardLayout/MenteeLayout/MenteeSidebar";
import ApiRequest from '../../../Services/ApiRequest';
import EducationCard from './EducationCard';
import SkillsCard from './SkillsCard';
import WorkExpCard from './WorkExpCard';
import { RouteGuard } from '../../../Services/RouteGuard';
import CustomModal from "../../../Components/Modal"
import { Link } from 'react-router-dom';


class Profile extends React.Component {
    state = {
        personalInfo: [],
        show: false,
        countries: [],
        image: ''
    }
    componentDidMount() {
        RouteGuard('Profile');
        this.getPersonalInfo();
        this.getCountries()
    }
    getPersonalInfo = async () => {
        const profile = await ApiRequest.getRequest('/getUserInfo');
        console.log(profile);
        if (profile && profile.status === 200) {
            this.setState({
                personalInfo: profile.data.userInfo,
                image: profile.data.userInfo?.[0]?.personal_info?.profile_image
            })
        }
    }
    getCountries = async () => {
        const getCountries = await ApiRequest.getRequest('/getCountries');
        if (getCountries && getCountries.data.countries && getCountries.status === 200) {
            this.setState({
                countries: getCountries.data.countries
            })
        }
    }
    handleModalClose = () => {
        this.setState({
            show: !this.state.show
        })
    }
    onChange = () => {
        this.getPersonalInfo();
    }
    render() {
        return (
            <div className="container-fluid dashboard-body-bg p-0">
                <div className='dashboard'>
                    <MenteeSidebar />
                    <div className='dashboard-app'>
                        <HeaderMenteeDashboard />
                        <div className='container-fluid ProfileWrap'>
                            <div className="row mar-width-0 ProfileInner-0">
                                <div className="col-md-12">
                                    <div className="row mar-width-0 ProfileInner0-1">

                                        <div className="col-md-6">
                                            <div className="profile-data">
                                                <img className="Rectangle-1" src={this.state.image ? process.env.REACT_APP_BASEURL + this.state.image : ''} alt="" />
                                                <h4>{this.state.personalInfo?.[0]?.first_name} {this.state.personalInfo?.[0]?.last_name}</h4>
                                            </div>

                                        </div>
                                        <div className="col-md-6 text-right mt-2">
                                            <Link to="/Settings"><img src={Pencil} alt="" /></Link>
                                        </div>
                                        <div className="col-md-6 pt--1">
                                            <h6>UK, London <br />
                                                Graphic Designer at Triixa Technologies</h6>
                                        </div>
                                        <div className="col-md-6  text-right social-icons-profile">
                                            <img src={Twit2} alt="" />
                                            <img src={Fb2} alt="" />
                                        </div>
                                    </div>
                                </div>
                            </div>
                            <div className="row mar-width-0 ProfileInner-1">
                                <div className="col-md-12">
                                    <h4>Summary</h4>
                                    <p>Lorem ipsum, or lipsum as it is sometimes known, is dummy text used in laying out print, graphic or web designs. The passage is attributed to an unknown typesetter in the 15th century who is thought to have scrambled parts of Cicero's De Finibus Bonorum et Malorum for use in a type specimen book.</p>
                                </div>
                            </div>
                            <SkillsCard personalInfo={this.state.personalInfo} onChange={this.onChange} />
                            <div className="row mar-width-0 ProfileInner-3">
                                <div className="col-md-6">
                                    <EducationCard personalInfo={this.state.personalInfo} onChange={this.onChange} />

                                </div>
                                <div className="col-md-6">
                                    <WorkExpCard personalInfo={this.state.personalInfo} countries={this.state.countries} onChange={this.onChange} />

                                </div>
                            </div>
                        </div>
                    </div>

                </div>
            </div>
        )
    }
}

export default Profile;

