import React from "react";
import Pencil from "../../../assets/images/DashboardImgs/pencil1.png";
import Plus2 from "../../../assets/images/DashboardImgs/plus-square.png";
import Work from "../../../assets/images/DashboardImgs/work.png";
import moment from 'moment';
import CustomModal from "../../../Components/Modal";
import ApiRequest from "../../../Services/ApiRequest";
import Select from 'react-select'
import User from "../../../assets/images/user.png";
import Polygon2 from "../../../assets/images/angle-down.png";
import Building from "../../../assets/images/building1.png";
import Calendar from "../../../assets/images/calendar.png";



class WorkExpCard extends React.Component {
    state = {
        experience: [],
        show: false,
        personalInfo: [],
        countries: [],
        country: {},
        city: {},
        cities: [],
        errors: {},
        expId: '',
        modalBtnText: 'Save'
    }
    static getDerivedStateFromProps(props, state) {
        return {
            experience: props.personalInfo?.[0]?.work_exp,
            personalInfo: props.personalInfo?.[0],
            countries: props?.countries,
        };
    }
    componentDidMount() {
    }
    experience = () => {
        if (this.state?.experience) {
            return this.state?.experience.map(el => {
                return (
                    <>
                        <h4>{el.job_title}<span>&nbsp; {moment(el.start_date).format("DD MMM YYYY")} - {moment(el.end_date).format("DD MMM YYYY")}</span> <img className="cursor-pointer" src={Pencil} alt="" onClick={() => this.onEditCard(el.id)} /></h4>
                        <h6>{el.company_name} {el?.city?.name}, {el?.country?.name}</h6>
                        <hr />
                    </>
                )
            })
        }
    }
    onChangeCountry = (event) => {
        console.log(event)
        const { value, label } = event
        this.setState({
            country_id: value,
            country: {
                value: value,
                label: label
            }
        })
        this.getCityByCountryID(value);
    }
    onChangeCity = (event) => {
        const { value, label } = event
        this.setState({
            city_id: value,
            city: {
                value: value,
                label: label
            }
        })
    }
    selectToCountries = () => {
        if (this.state?.countries) {
            let option = [];
            this.state.countries.map(el => {
                let arr = {
                    value: el.id,
                    label: el.name
                };
                option.push(arr);
            })
            return (
                <Select options={option} onChange={this.onChangeCountry} value={this.state.country} />
            );
        }
    }
    selectToCities = () => {
        if (this.state?.cities) {
            let option = [];
            this.state.cities.map(el => {
                let arr = {
                    value: el.id,
                    label: el.name
                };
                option.push(arr);
            })
            return (
                <Select options={option} onChange={(e) => this.onChangeCity(e)} value={this.state.city} />
            );
        }
    }
    getCityByCountryID = async (id) => {
        if (id !== undefined) {
            const response = await ApiRequest.getRequest(`/getCountryCities/${id}`);
            if (response && response.status === 200) {
                this.setState({
                    cities: response.data.cities,

                })
            }
        }
    }

    handleModalClose = () => {
        this.setState({
            show: !this.state.show,
            modalBtnText: 'Save',
            job_title: '',
            company_name: '',
            start_date: '',
            end_date: '',
            country_id: '',
            country: {},
            city: {},
            city_id: '',
            expId: '',
        })
    }
    handleChange = (e) => {
        const { name, value } = e.target;
        this.setState({
            [name]: value
        })
    }
    onChange = (event) => {
        const { name, value } = event.target
        this.setState({
            [name]: value
        })
    }
    handleSubmit = async (e) => {
        e.preventDefault();
        const { job_title, company_name, country_id, city_id, start_date, end_date } = this.state;
        let { jobError, companyError, countryError, cityError, startDateError, endDateError } = '';
        if (!job_title) {
            jobError = "This field is required"
        }
        if (!company_name) {
            companyError = "This field is required"
        }
        if (!country_id) {
            countryError = "This field is required"
        }
        if (!city_id) {
            cityError = "This field is required"
        }
        if (!start_date) {
            startDateError = "This field is required"
        }
        if (!end_date) {
            endDateError = "This field is required"
        }
        this.setState({
            errors: {
                jobError: jobError,
                companyError: companyError,
                countryError: countryError,
                cityError: cityError,
                startDateError: startDateError,
                endDateError: endDateError
            }
        })
        if (jobError || companyError || countryError || cityError || startDateError || endDateError) {
            return;
        }

        let arr = {
            job_title: job_title,
            company_name: company_name,
            country: country_id,
            city: city_id,
            start_date: start_date,
            end_date: end_date,
        }
        const response = await ApiRequest.postRequest('/addWorkExperience', arr)
        console.log(response);
        if (response && response.status === 200) {
            this.props.onChange();
            this.handleModalClose();
        }

    }

    // Edit Experience Card
    onEditCard = async (id) => {
        // alert(id);
        const response = await ApiRequest.getRequest('/workexperience/' + id);
        console.log(response);
        if (response && response.status === 200 && response.data?.WorkExperience?.[0]) {
            const val = response.data.WorkExperience[0]
            this.setState({
                job_title: val.job_title,
                company_name: val.company_name,
                start_date: val.start_date,
                end_date: val.end_date,
                country_id: val.country.id,
                country: {
                    value: val.country.id,
                    label: val.country.name,
                },
                city: {
                    value: val.city.id,
                    label: val.city.name,
                },
                city_id: val.city.id,
                expId: id,
                show: !this.state.show,
                modalBtnText: 'Update'

            })
        }
    }

    handleUpdate = async (e) => {
        e.preventDefault();
        const { job_title, company_name, country_id, city_id, start_date, end_date } = this.state;
        console.log(this.state)
        let { jobError, companyError, countryError, cityError, startDateError, endDateError } = '';
        if (!job_title) {
            jobError = "This field is required"
        }
        if (!company_name) {
            companyError = "This field is required"
        }
        if (!country_id) {
            countryError = "This field is required"
        }
        if (!city_id) {
            cityError = "This field is required"
        }
        if (!start_date) {
            startDateError = "This field is required"
        }
        if (!end_date) {
            endDateError = "This field is required"
        }
        this.setState({
            errors: {
                jobError: jobError,
                companyError: companyError,
                countryError: countryError,
                cityError: cityError,
                startDateError: startDateError,
                endDateError: endDateError
            }
        })
        if (jobError || companyError || countryError || cityError || startDateError || endDateError || !this.state.expId) {
            return;
        }

        let arr = {
            job_title: job_title,
            company_name: company_name,
            country: country_id,
            city: city_id,
            start_date: start_date,
            end_date: end_date,
        }
        const response = await ApiRequest.postRequest(`/addWorkExperience/${this.state.expId}`, arr)
        console.log(response);
        if (response && response.status === 200) {
            this.props.onChange();
            this.handleModalClose();
        }
    }

    render() {
        if (!this.state.cities.length) {
            this.getCityByCountryID(this.state.personalInfo?.country?.id)
        }
        return (
            <>
                <div className="row mar-width-0 bg-profile">
                    <div className="row mar-width-0 ProfileInner3-1">
                        <div className="col-md-6">
                            <h5><img src={Work} alt="" /> Work</h5>
                        </div>
                        <div className="col-md-6 text-right">
                            <img className="plus-skills cursor-pointer" src={Plus2} alt="" onClick={() => this.handleModalClose()} />
                        </div>
                    </div>
                    <div className="row mar-width-0 ProfileInner3-2">
                        {this.experience()}
                    </div>
                </div>
                <CustomModal show={this.state.show} closeBtn={this.handleModalClose} heading="Modal" onSubmit={this.handleSubmit} btnText={this.state.modalBtnText} onUpdate={this.handleUpdate}>
                    <div className="form_section_one  form-wrap form-section">
                        <div className="row ">
                            <div className="col-md-12">
                                <div className="form-group">
                                    <label htmlFor="exampleInputEmail13">Job Title</label>
                                    <div className={`select-style-2 w-100 `}>
                                        <select name="job_title" onChange={this.onChange} value={this.state.job_title}>
                                            <option disable>Select options</option>
                                            <option value="Backend Developer">Backend Developer</option>
                                            <option value="Frontend Developer">Frontend Developer</option>
                                            <option value="Graphic Designer">Graphic Designer</option>
                                        </select>
                                        <img src={User} className="user-icon2" alt="" />
                                        <img src={Polygon2} className="Polygon-icon" alt="" />
                                        <span className="error">{ }</span>
                                    </div>
                                </div>
                            </div>

                            <div className="col-md-12">
                                <div className="form-group position-relative">
                                    <label htmlFor="exampleInputEmail11">Company Name</label>
                                    <input type="text" className={`form-control`} onChange={this.onChange} id="exampleInputEmail11"
                                        name="company_name"
                                        value={this.state.company_name}
                                    />
                                    <img src={Building} className="user-icon" alt="" />
                                    <span className="error">{ }</span>
                                </div>
                            </div>

                            <div className="col-md-12">
                                <div className="form-group position-relative">
                                    <label htmlFor="exampleInputEmail13">Country</label>
                                    <div className={`select-2 w-100 `}>
                                        {
                                            this.selectToCountries()
                                        }
                                    </div>
                                    <span className="error">{ }</span>
                                </div>
                            </div>

                            <div className="col-md-12">
                                <div className="form-group">
                                    <label htmlFor="exampleInputEmail13">City</label>
                                    <div className={`select-2 w-100`}>
                                        {
                                            this.selectToCities()
                                        }
                                    </div>
                                </div>
                            </div>

                            <div className="col-md-12">
                                <div className="form-group position-relative">
                                    <label htmlFor="exampleInputEmail11">Date of work (From)</label>
                                    <input type="date" className={`form-control`} id="exampleInputEmail11"
                                        name="start_date" onChange={this.onChange} value={this.state.start_date}
                                    />
                                    <img src={Calendar} className="user-icon" alt="" />
                                    <span className="error"></span>
                                </div>
                            </div>

                            <div className="col-md-12">
                                <div className="form-group position-relative">
                                    <label htmlFor="exampleInputEmail11" className="">To</label>
                                    <input type="date" className={`form-control`} id="exampleInputEmail11"
                                        name="end_date"
                                        onChange={this.onChange}
                                        value={this.state.end_date}
                                    />
                                    <img src={Calendar} className="user-icon" alt="" />
                                    <span className="error">{ }</span>
                                </div>
                            </div>
                        </div>
                    </div>

                </CustomModal>
            </>
        )
    }
}

export default WorkExpCard;