import React from "react";
import Star2 from "../../../assets/images/DashboardImgs/Star2.png";
import Plus2 from "../../../assets/images/DashboardImgs/plus-square.png";
import Skills2 from "../../../assets/images/DashboardImgs/Skills2.png";
import { element } from "prop-types";
import CustomModal from "../../../Components/Modal";
import AddSkill from "../../../assets/images/add-skill.png";
import Polygon2 from "../../../assets/images/angle-down.png";
import ApiRequest from "../../../Services/ApiRequest";


class SkillsCard extends React.Component {
    state = {
        show: false,
        error: {},
        skill_one: false,
        skill_two: false,
        skill_three: false,
        skill_four: false,
        skill_five: false,
        skill: '',
        strength: '',
        modalBtnText: 'Save'


    }
    skillsTag = () => {
        if (this.props?.personalInfo[0]?.skills) {
            return this.props.personalInfo[0]?.skills.map(element => {
                return (
                    <>
                        <span key={element.id}><img src={Star2} alt="" />  {element.skill}</span>
                    </>
                )
            })
        }
    }
    handleModalClose = () => {
        this.setState({
            show: !this.state.show,
            skill: '',
            strength: ''
        })
        const skills = ['skill_one', 'skill_two', 'skill_three', 'skill_four', 'skill_five'];
        skills.forEach((el, val) => {
            this.setState({
                [el]: false
            })
        })
    }
    handleChange = (e) => {
        const { name, value } = e.target;
        this.setState({
            [name]: value
        })
    }
    /**
     * Skills form input change handling
     * @param  {object} event
     */
    onChangeSkill = (event) => {
        const { name, value } = event.target;
        const skills = ['skill_one', 'skill_two', 'skill_three', 'skill_four', 'skill_five'];
        var arr = {
            skill: this.state.skill,
            strength: this.state.strength
        }
        this.setState({
            [name]: value
        }, () => {
            if (name === 'strength') {
                skills.forEach((el, val) => {
                    if (val < this.state.strength) {
                        this.setState({
                            [el]: true
                        })
                    } else {
                        this.setState({
                            [el]: false
                        })
                    }
                });
            }
        })
    }

    handleSubmit = async (e) => {
        e.preventDefault();
        const { skill, strength } = this.state;
        let { skillNameError, skillStrengthError } = '';
        if (!skill) {
            skillNameError = "This field is required";
        }
        if (!strength) {
            skillStrengthError = "This field is required";
        }
        this.setState({
            error: {
                skillNameError: skillNameError,
                skillStrengthError: skillStrengthError
            }
        })
        if (skillNameError || skillStrengthError) {
            return
        }
        const response = await ApiRequest.postRequest(`/addSkill`, { skill, strength })
        if (response && response.status === 200) {
            this.props.onChange();
            this.handleModalClose();
        }
    }

    render() {
        return (
            <>
                <div className="row mar-width-0 ProfileInner-2">
                    <div className="col-md-12">
                        <h4><img src={Skills2} alt="" /> Skills</h4>
                        {this.skillsTag()}
                        <img className="plus-skills cursor-pointer" src={Plus2} alt="" onClick={() => this.handleModalClose()} />
                    </div>
                </div>
                <CustomModal show={this.state.show} closeBtn={this.handleModalClose} heading="Skill Model" onSubmit={this.handleSubmit} btnText={this.state.modalBtnText} onUpdate={this.handleUpdate}>
                    <div className="form_section_one  form-wrap form-section">

                        <div className="row mar-width-0">
                            <div className="col-md-12">
                                <div className="form-group">
                                    <label htmlFor="exampleInputEmail13">Add Skill</label>
                                    <div className={`select-style-2 w-100 ${this.state.error.skillNameError ? 'error-border' : ''}`}>
                                        <select name="skill" onChange={this.handleChange} value={this.state.skillName}>
                                            <option disable>Select options</option>
                                            <option value="PHP">PHP</option>
                                            <option value="Javascript">Javascript</option>
                                        </select>
                                        <img src={AddSkill} className="user-icon2" alt="" />
                                        <img src={Polygon2} className="Polygon-icon" alt="" />
                                    </div>
                                    <span className="error">{this.state.error.skillNameError}</span>
                                </div>
                            </div>
                            <div className="col-md-9">
                                <div className="squaredOne">
                                    <input type="checkbox" className="skillStrength" onChange={this.onChangeSkill} value="1" id="squaredOne" name="strength"
                                        checked={this.state.skill_one}
                                    />
                                    <label htmlFor="squaredOne"></label>
                                </div>
                                <div className="squaredOne">
                                    <input type="checkbox" className="skillStrength" onChange={this.onChangeSkill} value="2" id="squaredOne1" name="strength"
                                        checked={this.state.skill_two}
                                    />
                                    <label htmlFor="squaredOne1"></label>
                                </div>
                                <div className="squaredOne">
                                    <input type="checkbox" className="skillStrength" onChange={this.onChangeSkill} value="3" id="squaredOne2" name="strength"
                                        checked={this.state.skill_three}
                                    />
                                    <label htmlFor="squaredOne2"></label>
                                </div>
                                <div className="squaredOne">
                                    <input type="checkbox" className="skillStrength" onChange={this.onChangeSkill} value="4" id="squaredOne3" name="strength"
                                        checked={this.state.skill_four}
                                    />
                                    <label htmlFor="squaredOne3"></label>
                                </div>
                                <div className="squaredOne">
                                    <input type="checkbox" className="skillStrength" onChange={this.onChangeSkill} value="5" id="squaredOne4" name="strength"
                                        checked={this.state.skill_five}
                                    />
                                    <label htmlFor="squaredOne4"></label>
                                </div>
                                <span className="error">{this.state.error.skillStrengthError}</span>
                            </div>
                        </div>
                    </div>

                </CustomModal>
            </>
        )
    }
}

export default SkillsCard